package p1689

import "testing"

func Test_minPartitions(t *testing.T) {
	type args struct {
		n string
	}
	tests := []struct {
		name string
		args args
		want int
	}{
		{"Example 1", args{n: "32"}, 3},
		{"Example 2", args{n: "82734"}, 8},
		{"Example 3", args{n: "27346209830709182346"}, 9},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := minPartitions(tt.args.n); got != tt.want {
				t.Errorf("minPartitions() = %v, want %v", got, tt.want)
			}
		})
	}
}

func bench(f func(n string) int, b *testing.B) {
	b.ReportAllocs()
	for n := 0; n < b.N; n++ {
		f("")
		f("")
		f("")
		f("")
	}
}

func Benchmark_minPartitions(b *testing.B) {
	bench(minPartitions, b)
}

func Benchmark_minPartitions0(b *testing.B) {
	bench(minPartitions0, b)
}
